/**
 * Model domain-separation for the Amplituhedron prefix-residual cache key.
 *
 * Residuals/KV are weight-specific. The consolidated mesh swaps models on ONE
 * service, so a model-agnostic prefix hash let a residual captured under model
 * A be replayed for model B sharing prefix tokens → cross-prompt contamination.
 * These assertions lock in: (1) the legacy no-domain hash is unchanged, and
 * (2) distinct model domains map identical tokens to distinct prefix hashes.
 */

import { describe, test, expect } from '@a0n/gnosis/test';
import { prefixHashU64 } from '../pipeline.ts';

describe('prefixHashU64 model domain separation', () => {
  const tokens = new Uint32Array([1, 2, 3, 5, 8, 13, 21]);

  test('no-domain hash is stable (legacy token-only key, byte-identical)', async () => {
    const a = await prefixHashU64(tokens);
    const b = await prefixHashU64(new Uint32Array([1, 2, 3, 5, 8, 13, 21]));
    expect(a).toBe(b);
    expect(a).toMatch(/^[0-9]+$/);
  });

  test('a domain changes the hash vs. no domain', async () => {
    const bare = await prefixHashU64(tokens);
    const scoped = await prefixHashU64(tokens, 'mistral-7b-instruct-v0.3-q4km');
    expect(scoped).not.toBe(bare);
  });

  test('different models map identical tokens to different hashes', async () => {
    const mistral = await prefixHashU64(tokens, 'mistral-7b-instruct-v0.3-q4km');
    const qwen = await prefixHashU64(tokens, 'qwen2.5-7b');
    expect(mistral).not.toBe(qwen);
  });

  test('same model + same tokens is deterministic (cache still hits within a model)', async () => {
    const a = await prefixHashU64(tokens, 'mistral-7b-instruct-v0.3-q4km');
    const b = await prefixHashU64(
      new Uint32Array([1, 2, 3, 5, 8, 13, 21]),
      'mistral-7b-instruct-v0.3-q4km',
    );
    expect(a).toBe(b);
  });
});
